CREATE TABLE IF NOT EXISTS `indicadores` (
`id` int(11) NOT NULL PRIMARY KEY AUTO_INCREMENT ,
  `indicador` varchar(15) DEFAULT NULL,
  `texto` varchar(255) DEFAULT NULL,
  `valorIndicador` int(1) DEFAULT NULL,
  `valorable` varchar(1) DEFAULT NULL,
  `valorInstrum` int(1) ,
  `subvalorInstrum` int(1),
  `titulo` varchar(1) DEFAULT NULL,
  `otro` varchar(2) DEFAULT NULL
) ENGINE=InnoDB ;

